defmodule MyAppWeb.PostLive.Show do
  use MyAppWeb, :live_view
  import Phoenix.HTML, only: [html_escape: 1]

  def mount(%{"id" => id}, _session, socket) do
    post = get_post(id)
    {:ok, assign(socket, post: post, sanitized_content: sanitize_html(post.content))}
  end

  def render(assigns) do
    ~H"""
    <div class="post-container">
      <h1><%= @post.title %></h1>
      <div class="post-meta">
        <span>By <%= @post.author %></span>
        <span><%= @post.inserted_at %></span>
      </div>
      <div class="post-content">
        <%= Phoenix.HTML.raw(@sanitized_content) %>
      </div>
    </div>
    """
  end

  defp sanitize_html(content) do
    HtmlSanitizeEx.basic_html(content)
  end

  defp get_post(id) do
    %{
      id: id,
      title: "Sample Post",
      author: "John Doe",
      content: "<p>User content here</p>",
      inserted_at: DateTime.utc_now()
    }
  end
end